// Generated masking functions for candidates
export function maskCandidate<T extends Record<string, any>>(record: T, ctx: AppContext): T {
  const masked: any = { ...record };

  // email: show to admin, owner
  if (!(ctx.roles?.some(r => ['admin', 'owner'].includes(r)))) {
    if (masked['email'] != null) {
      masked['email'] = masks.email(masked['email']);
    }
  }

  // phone: show to admin, owner
  if (!(ctx.roles?.some(r => ['admin', 'owner'].includes(r)))) {
    if (masked['phone'] != null) {
      masked['phone'] = masks.phone(masked['phone']);
    }
  }

  // internalNotes: show to admin, owner
  if (!(ctx.roles?.some(r => ['admin', 'owner'].includes(r)))) {
    if (masked['internalNotes'] != null) {
      masked['internalNotes'] = masks.redact(masked['internalNotes']);
    }
  }

  // legalName: show to admin, owner
  if (!(ctx.roles?.some(r => ['admin', 'owner'].includes(r)))) {
    if (masked['legalName'] != null) {
      masked['legalName'] = masks.name(masked['legalName']);
    }
  }

  // governmentId: show to admin, owner
  if (!(ctx.roles?.some(r => ['admin', 'owner'].includes(r)))) {
    if (masked['governmentId'] != null) {
      masked['governmentId'] = masks.ssn(masked['governmentId']);
    }
  }

  // resumeUrl: show to admin, owner OR owner
  if (!(ctx.roles?.some(r => ['admin', 'owner'].includes(r)) || record.ownerId === ctx.userId)) {
    if (masked['resumeUrl'] != null) {
      masked['resumeUrl'] = masks.redact(masked['resumeUrl']);
    }
  }

  return masked as T;
}

export function maskCandidates<T extends Record<string, any>>(records: T[], ctx: AppContext): T[] {
  return records.map(r => maskCandidate(r, ctx));
}

